async function processFile(filePath: string) {
  try {
    const base64File = fs.readFileSync(filePath, { encoding: "base64" });

    const ocrResponse = await fetch("https://api.ocr.space/parse/image", {
      method: "POST",
      headers: {
        apikey: process.env.OCR_API_KEY,
        "Content-Type": "application/x-www-form-urlencoded",
      },
      body: new URLSearchParams({
        base64image: `data:application/pdf;base64,${base64File}`,
        isOverlayRequired: "true",
        language: "eng",
      }),
    });

    const result = await ocrResponse.json();
    if (!result || !result.ParsedResults) {
      return { error: "OCR API failed", percentage: null };
    }

    const extractedText = result.ParsedResults[0]?.ParsedText || "";
    console.log("Extracted OCR Text:\n", extractedText);

    // Improved regex to extract only valid subjects and marks
    const marksPattern = /([A-Za-z\s]{3,30})\s+(\d{1,3})\s*\/\s*(\d{2,3})/g;
    let match;
    let extractedMarks = [];

    while ((match = marksPattern.exec(extractedText)) !== null) {
      let subject = match[1].trim();
      let obtainedMarks = parseInt(match[2], 10);
      let subjectTotalMarks = parseInt(match[3], 10);

      extractedMarks.push({ subject, obtainedMarks, subjectTotalMarks });
    }

    // Remove irrelevant subjects
    const unwantedWords = [
      "certificate",
      "qualification",
      "mark sheet",
      "examination",
      "bhiwani",
    ];
    extractedMarks = extractedMarks.filter(
      (entry) =>
        !unwantedWords.some((word) =>
          entry.subject.toLowerCase().includes(word)
        )
    );

    // Calculate valid total marks
    const validMarks = extractedMarks.filter(
      (entry) => entry.subjectTotalMarks >= 50 && entry.subjectTotalMarks <= 100
    );
    const totalObtained = validMarks.reduce(
      (sum, entry) => sum + entry.obtainedMarks,
      0
    );
    const totalMarks = validMarks.reduce(
      (sum, entry) => sum + entry.subjectTotalMarks,
      0
    );

    if (totalMarks === 0)
      return { error: "No valid marks found", percentage: null };

    const percentage = (totalObtained / totalMarks) * 100;

    return {
      marks: validMarks,
      percentage: parseFloat(percentage.toFixed(2)),
    };
  } catch (error) {
    console.error("Error processing file:", error);
    return { error: "Error processing file", percentage: null };
  }
}
